# ─── SHARED HELPERS ───────────────────────────────────────────────────────────

def eyebrow(text: str) -> ft.Text:
    return ft.Text(text.upper(), size=10, weight=ft.FontWeight.W_700,
                   color=HOT_PINK)


def page_title(text: str) -> ft.Text:
    return ft.Text(text, size=24, weight=ft.FontWeight.W_900, color=WHITE)


def page_sub(text: str) -> ft.Text:
    return ft.Text(text, size=13, color=MUTED)


def divider() -> ft.Container:
    return ft.Container(height=1, bgcolor=BORDER)


def gap(h: int = 16) -> ft.Container:
    return ft.Container(height=h)


def card(content: ft.Control, padding=24) -> ft.Container:
    return ft.Container(
        content=content,
        bgcolor=CARD,
        border_radius=12,
        padding=padding,
        border=ft.Border.all(1, BORDER),
    )


def badge(label: str, color: str = HOT_PINK) -> ft.Container:
    bg = "#1A0A10" if color == HOT_PINK else "#0A1A0A"
    return ft.Container(
        content=ft.Text(label, size=10, color=color, weight=ft.FontWeight.W_700),
        bgcolor=bg,
        border_radius=20,
        padding=ft.padding.Padding(10, 3, 10, 3),
        border=ft.Border.all(1, color),
    )


def stat_tile(value: str, label: str) -> ft.Container:
    return ft.Container(
        content=ft.Column(
            horizontal_alignment=ft.CrossAxisAlignment.CENTER,
            spacing=4,
            controls=[
                ft.Text(value, size=32, weight=ft.FontWeight.W_900, color=HOT_PINK),
                ft.Text(label, size=11, color=MUTED, text_align=ft.TextAlign.CENTER),
            ],
        ),
        bgcolor=CARD,
        border_radius=12,
        padding=ft.padding.Padding(20, 22, 20, 22),
        border=ft.Border.all(1, BORDER),
        expand=True,
    )


def pbar(label: str, pct: int, width: int = 340) -> ft.Column:
    """Percentage bar – pct is 0-100."""
    filled = max(2, int(width * pct / 100))
    return ft.Column(
        spacing=6,
        controls=[
            ft.Row(
                controls=[
                    ft.Text(label, size=13, color=LIGHT, expand=True),
                    ft.Text(f"{pct}%", size=12, color=HOT_PINK),
                ],
            ),
            ft.Stack(
                width=width, height=5,
                controls=[
                    ft.Container(width=width, height=5, border_radius=3, bgcolor=BORDER),
                    ft.Container(width=filled, height=5, border_radius=3, bgcolor=HOT_PINK),
                ],
            ),
        ],
    )


def section_header(eyebrow_txt: str, title_txt: str, sub_txt: str) -> ft.Column:
    return ft.Column(
        spacing=6,
        controls=[
            eyebrow(eyebrow_txt),
            gap(4),
            page_title(title_txt),
            page_sub(sub_txt),
            gap(20),
            divider(),
            gap(20),
        ],
    )


