# ─── SECTION: TIMELINE ────────────────────────────────────────────────────────

def build_timeline() -> ft.Column:
    weeks = [
        ("Week 1", "Project introduction — explored the core problems the app would solve, including blast scheduling, safety notifications, and remote GIS mapping in mining operations."),
        ("Week 2", "Planned the app features as a team: defined blast scheduling, push notifications, and remote GIS mapping. Established the role of lead developer and distributed responsibilities among the 20 members."),
        ("Week 3", "Started coding the application. Designed the basic user interface layout and defined the app's core workflow and navigation structure."),
        ("Week 4", "Integrated Firebase into the project for real-time data storage and synchronisation across all users on the platform."),
        ("Week 5", "Implemented the scheduling system, blast notifications, and Firebase-powered synchronisation between users to ensure all team members see live schedule updates."),
        ("Week 6", "Conducted testing across app features, fixed bugs found during QA, and verified that calculations and Firebase data storage were working correctly."),
        ("Week 7", "Prepared technical documentation and organised the codebase for GitHub — structured folders, wrote commit messages, and ensured contribution history was clean and verifiable."),
        ("Week 8", "Finalised the presentation slides, rehearsed for the group presentation, prepared for lead developer interview questions, and reviewed key topics including Firebase, GitHub workflows, and the app's full feature set."),
    ]

    rows = []
    for i, (wk, detail) in enumerate(weeks):
        is_last = i == len(weeks) - 1
        rows.append(
            ft.Row(
                vertical_alignment=ft.CrossAxisAlignment.START,
                spacing=0,
                controls=[
                    ft.Column(
                        horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                        width=36,
                        spacing=0,
                        controls=[
                            ft.Container(
                                width=14, height=14, border_radius=7,
                                bgcolor=HOT_PINK,
                                border=ft.Border.all(3, BG),
                                margin=ft.Margin(0,2,0,0),
                            ),
                            ft.Container(
                                width=2,
                                height=0 if is_last else 64,
                                bgcolor=BORDER,
                            ),
                        ],
                    ),
                    ft.Column(
                        expand=True,
                        spacing=4,
                        controls=[
                            ft.Text(wk, size=13, weight=ft.FontWeight.W_700, color=SOFT_PINK),
                            ft.Text(detail, size=13, color=LIGHT),
                            gap(4 if is_last else 10),
                        ],
                    ),
                ],
            )
        )

    return ft.Column(
        scroll=ft.ScrollMode("auto"),
        spacing=0,
        controls=[
            section_header(
                "Timeline",
                "Weekly Contribution Log",
                "A chronological record of my individual contributions to the group project.",
            ),
            card(ft.Column(spacing=0, controls=rows)),
            gap(24),
        ],
    )


# ─── SECTION: MATLAB ──────────────────────────────────────────────────────────

def build_matlab(page: ft.Page = None) -> ft.Column:
    courses = [
        ("MATLAB Onramp",                                    True,  "Core",       "matlab_onramp"),
        ("Simulink Onramp",                                  True,  "Simulation", "simulink_onramp"),
        ("Machine Learning Onramp",                          True,  "AI/ML",      "machine_learning"),
        ("MATLAB Desktop Tools and Troubleshooting Scripts", True,  "Tools",      "desktop_tools"),
        ("Explore Data with MATLAB Plots",                   True,  "Data",       "matlab_plots"),
        ("Make and Manipulate Matrices",                     True,  "Math",       "make_matrices"),
        ("Calculations with Vectors and Matrices",           True,  "Math",       "vectors_matrices"),
        ("Deep Learning Onramp",                             False, "AI/ML",      None),
    ]

    def show_cert(cert_key):
        def _handler(e):
            if cert_key is None:
                return
            img = ft.Image(src=open(f"assets/{cert_key}.png","rb").read(), width=700, height=460, border_radius=10)
            dlg = ft.AlertDialog(bgcolor=CARD, content=ft.Container(content=img, width=720))
            page.show_dialog(dlg)
        return _handler

    def close_dlg(e, dlg):
        dlg.open = False
        page.update()

    tiles = []
    for name, done, tag, cert_key in courses:
        tile = ft.Container(
            content=ft.Row(
                vertical_alignment=ft.CrossAxisAlignment.CENTER,
                spacing=12,
                controls=[
                    ft.Icon(
                        ft.Icons.CHECK_CIRCLE_ROUNDED if done
                        else ft.Icons.RADIO_BUTTON_UNCHECKED,
                        color=HOT_PINK if done else MUTED,
                        size=20,
                    ),
                    ft.Text(name, size=13,
                            color=WHITE if done else MUTED, expand=True),
                    badge(tag),
                    ft.Icon(
                        ft.Icons.OPEN_IN_NEW if done else ft.Icons.LOCK_OUTLINE,
                        color=HOT_PINK if done else MUTED, size=14
                    ),
                ],
            ),
            padding=ft.padding.Padding(18, 14, 18, 14),
            border=ft.Border.only(bottom=ft.BorderSide(1, BORDER)),
            ink=True if done else False,
            border_radius=0,
            on_click=show_cert(cert_key) if done else None,
            tooltip="Click to view certificate" if done else "Not yet completed",
        )
        tiles.append(tile)

    completed = sum(1 for _, d, _t, _k in courses if d)

    stats_row = ft.Row(
        spacing=12,
        controls=[
            card(ft.Column(
                horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                spacing=4,
                controls=[
                    ft.Text(str(completed), size=38,
                            weight=ft.FontWeight.W_900, color=HOT_PINK),
                    ft.Text("Completed", size=11, color=MUTED),
                ],
            ), padding=20),
            card(ft.Column(
                horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                spacing=4,
                controls=[
                    ft.Text("8", size=38,
                            weight=ft.FontWeight.W_900, color=SOFT_PINK),
                    ft.Text("Required", size=11, color=MUTED),
                ],
            ), padding=20),
            card(ft.Column(
                horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                spacing=4,
                controls=[
                    ft.Text("87.5 %", size=38,
                            weight=ft.FontWeight.W_900, color=WHITE),
                    ft.Text("Progress", size=11, color=MUTED),
                ],
            ), padding=20),
        ],
    )

    note = ft.Container(
        content=ft.Row(
            spacing=10,
            controls=[
                ft.Icon(ft.Icons.INFO_OUTLINE_ROUNDED, color=SOFT_PINK, size=16),
                ft.Text(
                    "Certificate screenshots are stored in the /evidence/matlab/ directory "
                    "of the project repository and linked from the GitHub Evidence section.",
                    size=12, color=LIGHT, expand=True,
                ),
            ],
        ),
        bgcolor="#0D0010",
        border_radius=8,
        padding=14,
        border=ft.Border.all(1, DEEP_PINK),
    )

    return ft.Column(
        scroll=ft.ScrollMode("auto"),
        spacing=0,
        controls=[
            section_header(
                "MATLAB Hub",
                "MathWorks Achievement Hub",
                "Proof of completion for 8 self-paced courses from the MathWorks Learning Center.",
            ),
            stats_row,
            gap(16),
            card(ft.Column(spacing=0, controls=tiles), padding=0),
            gap(16),
            note,
            gap(24),
        ],
    )


# ─── SECTION: BLOG ────────────────────────────────────────────────────────────

def build_blog(page: ft.Page = None) -> ft.Column:
    posts = [
        {
            "title":   "How Firebase Enables Real-Time Data Sync",
            "date":    "May 2026",
            "tag":     "Database",
            "summary": (
                "Firebase Firestore uses a NoSQL document model to store and sync data across "
                "all connected clients in real time. In Blast Master Pro, every schedule update "
                "written to Firestore is instantly pushed to all authorised users — no manual "
                "refresh required. This is achieved through Firestore's onSnapshot listeners, "
                "which stream changes as they happen."
            ),
            "math":    "Latency ≈ O(1)  →  real-time push vs O(n) polling",
        },
        {
            "title":   "Blast Scheduling Logic and Time Calculations",
            "date":    "May 2026",
            "tag":     "Core Concepts",
            "summary": (
                "A blast schedule requires computing safe time windows between events. Given a "
                "blast at time T with a clearance duration D and a buffer B, the next permitted "
                "blast start time is T + D + B. The ScheduleScreen component enforces this logic "
                "before allowing any new entry to be created or saved to Firebase."
            ),
            "math":    "Next Blast = T + D + B,   where D = clearance time, B = safety buffer",
        },
        {
            "title":   "Understanding GIS Coordinates in Mining Apps",
            "date":    "June 2026",
            "tag":     "Engineering Math",
            "summary": (
                "Geographic Information Systems (GIS) represent locations using latitude and "
                "longitude coordinates. The distance between two blast sites can be estimated "
                "using the Haversine formula, which accounts for the curvature of the Earth. "
                "This is critical in remote mining operations where accurate spatial data "
                "determines safe exclusion zones around active blast areas."
            ),
            "math":    "d = 2r · arcsin(√(sin²(Δφ/2) + cos φ₁ · cos φ₂ · sin²(Δλ/2)))",
        },
    ]

    def show_video(e):
        if page is None:
            return
        vid = fv.Video(
            playlist=[fv.VideoMedia(resource="/assets/myvideo.mp4")],
            width=700,
            height=400,
            autoplay=True,
        )
        dlg = ft.AlertDialog(bgcolor=CARD, content=ft.Container(content=vid, width=720))
        page.show_dialog(dlg)

    post_cards = []
    for p in posts:
        post_cards.append(
            ft.Container(
                content=ft.Column(
                    spacing=12,
                    controls=[
                        ft.Row(
                            controls=[
                                badge(p["tag"]),
                                ft.Text(p["date"], size=11, color=MUTED),
                            ],
                            alignment=ft.MainAxisAlignment.SPACE_BETWEEN,
                        ),
                        ft.Text(p["title"], size=17,
                                weight=ft.FontWeight.W_700, color=WHITE),
                        ft.Text(p["summary"], size=13, color=LIGHT),
                        ft.Container(
                            content=ft.Row(
                                spacing=8,
                                controls=[
                                    ft.Icon(ft.Icons.FUNCTIONS_ROUNDED,
                                            color=SOFT_PINK, size=15),
                                    ft.Text(p["math"], size=13, color=SOFT_PINK,
                                            font_family="monospace"),
                                ],
                                vertical_alignment=ft.CrossAxisAlignment.CENTER,
                            ),
                            bgcolor="#0D0008",
                            border_radius=8,
                            padding=ft.padding.Padding(14, 10, 14, 10),
                            border=ft.Border.all(1, DEEP_PINK),
                        ),
                    ],
                ),
                bgcolor=CARD,
                border_radius=12,
                padding=22,
                border=ft.Border.all(1, BORDER),
            )
        )
        post_cards.append(gap(12))

    video_card = ft.Container(
        content=ft.Row(
            spacing=8,
            controls=[
                ft.Icon(ft.Icons.PLAY_CIRCLE_OUTLINE_ROUNDED,
                        color=HOT_PINK, size=20),
                ft.Text("Watch video explanation",
                        size=14, color=HOT_PINK,
                        weight=ft.FontWeight.W_600),
            ],
            vertical_alignment=ft.CrossAxisAlignment.CENTER,
        ),
        bgcolor=CARD,
        border_radius=12,
        padding=22,
        border=ft.Border.all(1, BORDER),
        on_click=show_video,
        ink=True,
    )

    return ft.Column(
        scroll=ft.ScrollMode("auto"),
        spacing=0,
        controls=[
            section_header(
                "Technical Blog",
                "Confidence in Concepts",
                "Written explanations of core programming concepts with proper mathematical notation "
                "and an embedded video insert.",
            ),
            *post_cards,
            video_card,
            gap(24),
        ],
    )


# ─── SECTION: GITHUB ──────────────────────────────────────────────────────────

def build_github(page: ft.Page = None) -> ft.Column:
    commits = [
        ("#7dacba6", "Add ScheduleScreen component to README",       "main", "13 Jun 2026"),
        ("#5bf621e", "Update README.md",                             "main", "13 Jun 2026"),
        ("#bc40ffa", "Add ScheduleScreen component in scheduling file","main","13 Jun 2026"),
        ("#0beo2ab", "Initial commit — Blast Master Pro repository",  "main", "13 Jun 2026"),
    ]

    prs = [
        ("—",  "No pull requests raised individually.",  "N/A",  "Jun 2026", "—"),
    ]

    def show_github(e):
        if page is None:
            return
        img = ft.Image(src=open("assets/github_commits.png","rb").read(), width=700, height=400, border_radius=10)
        dlg = ft.AlertDialog(bgcolor=CARD, content=ft.Container(content=img, width=720))
        page.show_dialog(dlg)

    commit_rows = []
    for sha, msg, branch, date in commits:
        commit_rows.append(
            ft.Container(
                content=ft.Row(
                    vertical_alignment=ft.CrossAxisAlignment.CENTER,
                    spacing=10,
                    controls=[
                        ft.Text(sha[:7], size=11, color=HOT_PINK,
                                font_family="monospace", width=56),
                        ft.Text(msg, size=13, color=WHITE, expand=True),
                        badge(branch, SOFT_PINK if branch == "develop" else HOT_PINK),
                        ft.Text(date, size=11, color=MUTED, width=80),
                    ],
                ),
                padding=ft.padding.Padding(18, 12, 18, 12),
                border=ft.Border.only(bottom=ft.BorderSide(1, BORDER)),
                on_click=show_github,
                ink=True,
            )
        )

    pr_rows = []
    for num, title, status, date, reviews in prs:
        pr_rows.append(
            ft.Container(
                content=ft.Row(
                    vertical_alignment=ft.CrossAxisAlignment.CENTER,
                    spacing=10,
                    controls=[
                        ft.Icon(ft.Icons.MERGE_TYPE_ROUNDED, color=HOT_PINK, size=16),
                        ft.Text(num, size=12, color=SOFT_PINK,
                                weight=ft.FontWeight.W_700, width=46),
                        ft.Text(title, size=13, color=WHITE, expand=True),
                        badge(status),
                        ft.Text(reviews, size=11, color=MUTED, width=70),
                        ft.Text(date, size=11, color=MUTED, width=80),
                    ],
                ),
                padding=ft.padding.Padding(18, 12, 18, 12),
                border=ft.Border.only(bottom=ft.BorderSide(1, BORDER)),
            )
        )

    impact_card = ft.Container(
        content=ft.Column(
            spacing=12,
            controls=[
                ft.Row(
                    spacing=8,
                    controls=[
                        ft.Icon(ft.Icons.BOLT_ROUNDED, color=HOT_PINK, size=18),
                        ft.Text("Individual Impact on Engineering Modules",
                                size=14, weight=ft.FontWeight.W_700, color=WHITE),
                    ],
                    vertical_alignment=ft.CrossAxisAlignment.CENTER,
                ),
                ft.Text(
                    "ScheduleScreen Component — Built the core scheduling interface of Blast Master Pro. "
                    "The component retrieves blast schedule data directly from Firebase Firestore, "
                    "displays upcoming blasting times and their details to the user, and allows "
                    "authorised users to create and update schedules. It also supports push "
                    "notifications for planned blasts, ensuring all team members are alerted "
                    "in real time before a blast event occurs.",
                    size=13, color=LIGHT,
                ),
            ],
        ),
        bgcolor=CARD,
        border_radius=12,
        padding=22,
        border=ft.Border.all(1, BORDER),
    )

    return ft.Column(
        scroll=ft.ScrollMode("auto"),
        spacing=0,
        controls=[
            section_header(
                "GitHub Evidence",
                "Contribution Documentation",
                "Verifiable evidence of individual contributions to the 20-member team project.",
            ),
            ft.Text("Commit History", size=14,
                    weight=ft.FontWeight.W_700, color=SOFT_PINK),
            gap(8),
            card(ft.Column(spacing=0, controls=commit_rows), padding=0),
            gap(16),
            ft.Text("Pull Requests", size=14,
                    weight=ft.FontWeight.W_700, color=SOFT_PINK),
            gap(8),
            card(ft.Column(spacing=0, controls=pr_rows), padding=0),
            gap(16),
            ft.Text("Impact Summary", size=14,
                    weight=ft.FontWeight.W_700, color=SOFT_PINK),
            gap(8),
            impact_card,
            gap(24),
        ],
    )


